    DomainAction(action_id="dynamic_cutoff", name="Corte dinâmico", description="Aplica corte dinâmico ao pipeline retendo apenas o top 25% dos candidatos com base nos scores. Aciona quando pipeline está saturado e recruiter precisa focar nos melhores candidatos."),
