    DomainAction(action_id="classify_dreyfus", name="Classificar Dreyfus", description="Classifica o nível de proficiência do candidato no modelo Dreyfus (novice → expert) para competências técnicas. Aciona na avaliação de seniority para vagas técnicas."),
