    DomainAction(action_id="compare_candidates", name="Comparar candidatos", description="Compara candidatos selecionados lado a lado em dimensões de competência, score e fit cultural. Aciona quando recruiter tem múltiplos finalistas e precisa decidir quem avançar."),
    DomainAction(action_id="calibrate_model", name="Calibrar modelo", description="Calibra o modelo de triagem com feedback explícito do recrutador sobre candidatos aprovados e rejeitados. Aciona periodicamente para melhorar precisão da triagem automática."),
    DomainAction(action_id="explain_score", name="Explicar score", description="Explica detalhadamente como o score WSI do candidato foi calculado, indicando quais competências contribuíram e quais faltam. Aciona quando recruiter ou candidato questiona o resultado."),
    DomainAction(action_id="evaluate_rubric", name="Avaliar rubrica", description="Avalia candidato por rubrica estruturada com critérios e pesos específicos da vaga. Aciona para avaliação padronizada e comparável entre candidatos."),
    DomainAction(action_id="generate_questions", name="Gerar perguntas", description="Gera perguntas de triagem WSI personalizadas para a vaga com base nos requisitos e competências mapeadas. Aciona na configuração de nova vaga ou antes de entrevista estruturada."),
