    DomainAction(action_id="send_feedback", name="Enviar feedback", description="Envia feedback personalizado ao candidato sobre o resultado da triagem com pontos positivos e áreas de desenvolvimento. Aciona após rejeição quando empresa quer oferecer experiência de qualidade."),
    DomainAction(action_id="pre_qualify", name="Pré-qualificar", description="Pré-qualifica candidato com perguntas rápidas antes da triagem formal para filtrar desqualificadores objetivos (localização, salário, disponibilidade). Aciona como etapa zero antes do processo completo."),
